#!/usr/bin/env bash
set -euo pipefail

FSTAB="/etc/fstab"
MOUNT_POINT="/dev/shm"

# Ensure /etc/fstab has an entry for /dev/shm with noexec option
if grep -E -q "^\s*[^#].*\s+${MOUNT_POINT}\s+" "$FSTAB"; then
    # Entry exists - ensure it has noexec, nosuid, nodev (add noexec at minimum)
    awk -v mp="$MOUNT_POINT" '
    BEGIN { OFS="\t" }
    {
        if ($0 ~ /^[[:space:]]*#/ || NF < 4) { print; next }
        if ($2 == mp) {
            n = split($4, opts, ",")
            has_noexec = 0
            for (i = 1; i <= n; i++) {
                if (opts[i] == "noexec") has_noexec = 1
            }
            if (!has_noexec) {
                if ($4 == "defaults" || $4 == "") {
                    $4 = $4 ",noexec"
                } else {
                    $4 = $4 ",noexec"
                }
            }
            print
            next
        }
        print
    }
    ' "$FSTAB" > "${FSTAB}.tmp"
    mv "${FSTAB}.tmp" "$FSTAB"
    chmod 0644 "$FSTAB"
else
    # Add new entry
    printf "tmpfs\t%s\ttmpfs\tdefaults,nodev,nosuid,noexec\t0 0\n" "$MOUNT_POINT" >> "$FSTAB"
fi

# Apply to active mount
if mountpoint -q "$MOUNT_POINT"; then
    mount -o remount "$MOUNT_POINT"
else
    mount "$MOUNT_POINT"
fi

# Verify
if findmnt -no OPTIONS "$MOUNT_POINT" | grep -qw noexec; then
    echo "Successfully applied noexec to $MOUNT_POINT"
else
    echo "Failed to apply noexec to $MOUNT_POINT" >&2
    exit 1
fi

#!/bin/bash
set -euo pipefail

MOUNT_POINT="/dev/shm"
OPTION="nodev"

# Update /etc/fstab persistently
if grep -E "^\s*[^#].*\s+${MOUNT_POINT}\s+" /etc/fstab >/dev/null 2>&1; then
    # Existing entry - ensure nodev is in the options field
    awk -v mp="${MOUNT_POINT}" -v opt="${OPTION}" '
    BEGIN { OFS="\t" }
    {
        if ($0 ~ /^[[:space:]]*#/ || NF < 4) { print; next }
        if ($2 == mp) {
            n = split($4, opts, ",")
            found = 0
            for (i = 1; i <= n; i++) {
                if (opts[i] == opt) { found = 1; break }
            }
            if (!found) {
                if ($4 == "defaults" || $4 == "") {
                    $4 = $4 "," opt
                } else {
                    $4 = $4 "," opt
                }
            }
        }
        print
    }' /etc/fstab > /etc/fstab.tmp.$$
    mv /etc/fstab.tmp.$$ /etc/fstab
    chmod 0644 /etc/fstab
else
    # No entry - append one
    printf "tmpfs\t%s\ttmpfs\tdefaults,%s\t0 0\n" "${MOUNT_POINT}" "${OPTION}" >> /etc/fstab
fi

# Apply immediately
if mountpoint -q "${MOUNT_POINT}"; then
    mount -o remount "${MOUNT_POINT}"
else
    mount "${MOUNT_POINT}"
fi

# Verify
if findmnt -no OPTIONS "${MOUNT_POINT}" | tr ',' '\n' | grep -qx "${OPTION}"; then
    echo "Success: ${MOUNT_POINT} is mounted with ${OPTION}"
else
    echo "Error: ${MOUNT_POINT} does not have ${OPTION} option applied" >&2
    exit 1
fi

